var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흐음...... 남은 결재 서류는 내일까지 마무리하면 되겠군.","JPN":"ふむ……残りの決裁書類は明日までに仕上げればいいか。","ENG":"Hmm... I think I can sign the remaining documents tomorrow.","TWN":"嗯..... 剩下的審批文件到明天爲止完成就可以了。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다음은 보고서 차례인가?","JPN":"次は報告書か？","ENG":"Next, reports.","TWN":"下一個是輪到報告書嗎？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"알파트릭스 그룹은 계승권 분쟁으로 여전히 시끄럽군.","JPN":"アルファトリックスグループは相変わらず継承権争いで騒がしいな。","ENG":"Alphatrix Group is still embroiled in the bitter succession battle.","TWN":"阿爾法崔克斯集團因繼承權糾紛仍然吵鬧。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다음 주주 총회 날짜가......","JPN":"次の株主総会の日程は……","ENG":"Its next general shareholders' meeting is scheduled—","TWN":"下一次股東大會日期是....."},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"아빠! 도와 줘!","JPN":"パパ！　助けて！","ENG":"Daddy! Help!","TWN":"爸爸！幫幫我！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음? 시그마, 집무실에는 무슨 일이니?","JPN":"ん？　シグマか。執務室に何の用だい？","ENG":"Mm? Sigma, what brings you to my office?","TWN":"嗯？西格瑪，到辦公室有什麼事情嗎？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"무서운 애꾸눈 해적 아줌마가 날 잡아가려고 해!","JPN":"こわーい眼帯の海賊おばさんに連れていかれちゃう！","ENG":"That scary one-eyed pirate woman is trying to kidnap me!","TWN":"可怕的獨眼海賊大嬸想要抓我！"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"해적? 예전에 소란 피웠던 그 여자 말이냐?","JPN":"海賊……？　先日騒いでた彼女のことか？","ENG":"The pirate woman? The one who raised hell before?","TWN":"海賊？是以前跟你吵架的那個女生嗎？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"누가 해적 아줌마입니까. 회사에서는 직함으로 부르라고 했을 텐데요.","JPN":"誰が海賊おばさんですか。会社ではちゃんと役職名で呼ぶようにって言ってるでしょう？","ENG":"Who are you calling a pirate woman? I asked you to call me by my title when we're at work.","TWN":"誰是海賊大嬸啊？公司不是交代用職稱來稱呼嗎？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아, 누군가 했더니 자네였군.","JPN":"ああ、誰かと思えば……君のことだったのか。","ENG":"Ah, so it was you.","TWN":"啊，我還以為是誰呢，原來是你啊。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런데 잡아가다니 어디로? 치과 예약이라도 잡아 둔 건가?","JPN":"しかし連れていかれるって、どこへだ？\\n歯医者の予約でもあるのか？","ENG":"But kidnap her where? Did you get a dentist appointment for her?","TWN":"不過被抓去哪裡了？是幫我預約牙科了嗎？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"고물상이라면 모를까, 치과에 데려 갈 필요는 없을 것 같습니다만.","JPN":"リサイクルショップならまだしも、歯医者なんて行く必要ないでしょう。","ENG":"I don't think she needs to see a dentist. A junkman, maybe.","TWN":"如果是古物商還差不多，沒必要帶去牙科了吧。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"오늘은 관리국의 정기 안전 교육이 있는 날입니다.","JPN":"今日は管理局の定期安全教育の日です。","ENG":"Today we have a regular safety training class with the Administration.","TWN":"今天是管理局定期安全教育的日子。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"넘버링 라이선스를 보유한 태스크포스라면 모든 직원이 거쳐야 하는 필수 과정이죠.","JPN":"ナンバリングライセンスを持っているタスクフォースカンパニーの社員なら参加必須です。","ENG":"Every employee of licensed TASKFORCE companies must take the class.","TWN":"擁有編號許可的特遣勢力的話，所有員工必須要通過的過程。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"난 안 들어도 돼. 안전 수칙 같은 건 네트워크만 연결돼 있으면 언제든지 다운로드 받을 수 있는걸.","JPN":"私は要らないよ。安全ルールなんて、ネットワークさえ繋がっていればいつだってダウンロードできるんだもん。","ENG":"I don't have to. I can download the safety rules anytime from anywhere, so long as I'm online.","TWN":"我不需要聽，像安全規矩這種東西只要連接網路的話隨時都可以下載的。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저도 듣고 싶은 생각은 없습니다. 몇 년 동안 토씨 하나 안 틀리고 계속 같은 소리만 하는 자리니까요.","JPN":"私だって聞きたくないですよ。ここ数年、まったく同じ内容ですもの。","ENG":"I don't want to take it, either. It's been the same class, with no change whatsoever, for years.","TWN":"我也不想聽，因為這幾年下來都會講同樣的話。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 불참자가 생기면 저희 회사 입장이 곤란해집니다.","JPN":"ですが、会社としては不参加の人がいては困ります。","ENG":"But everyone has to take it, or our company will be in trouble.","TWN":"但是，如果有人不參加，我們公司的立場就會變得困擾。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};